import{_ as e,o as t,c as i,S as r}from"./chunks/framework.C6RQlTYc.js";const g=JSON.parse('{"title":"生成式 AI","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_5-generative_ai.md","filePath":"直击概念/17ai/s_ai_5-generative_ai.md","lastUpdated":1778207238000}'),l={name:"直击概念/17ai/s_ai_5-generative_ai.md"};function o(n,a,s,d,h,u){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="生成式-ai" tabindex="-1">生成式 AI <a class="header-anchor" href="#生成式-ai" aria-label="Permalink to &quot;生成式 AI&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>生成式 AI（Generative AI）是一类能够<strong>创造新内容</strong>的 AI 系统，包括文本、图像、音频、视频、代码等。与<strong>判别式 AI</strong>（只做分类和预测）不同，生成式 AI 学习的是数据的<strong>概率分布</strong>，从而能够生成与训练数据风格相似但又不完全相同的新内容。</p><p>核心公式可以理解为：给定训练数据分布 P(data)，生成模型学习 P(new | context)，在给定上下文后生成全新的内容。</p><h2 id="判别式-ai-vs-生成式-ai" tabindex="-1">判别式 AI vs 生成式 AI <a class="header-anchor" href="#判别式-ai-vs-生成式-ai" aria-label="Permalink to &quot;判别式 AI vs 生成式 AI&quot;">​</a></h2><table><thead><tr><th>维度</th><th>判别式 AI</th><th>生成式 AI</th></tr></thead><tbody><tr><td>目标</td><td>学习决策边界 P(y</td><td>x)</td></tr><tr><td>输出</td><td>分类标签、数值</td><td>文本、图片、音频等新内容</td></tr><tr><td>典型任务</td><td>图像分类、垃圾邮件检测</td><td>文本生成、图像生成、对话</td></tr><tr><td>举例</td><td>ResNet、XGBoost</td><td>GPT-4、Stable Diffusion</td></tr></tbody></table><h2 id="三大核心技术路线" tabindex="-1">三大核心技术路线 <a class="header-anchor" href="#三大核心技术路线" aria-label="Permalink to &quot;三大核心技术路线&quot;">​</a></h2><h3 id="自回归模型-autoregressive-models" tabindex="-1">自回归模型（Autoregressive Models） <a class="header-anchor" href="#自回归模型-autoregressive-models" aria-label="Permalink to &quot;自回归模型（Autoregressive Models）&quot;">​</a></h3><p>逐个元素（token/pixel）地生成，每个新元素依赖之前已生成的内容。</p><ul><li>代表：GPT 系列、Llama、Claude</li><li>应用：文本生成、代码补全</li><li>特点：生成质量高，但逐 token 生成速度较慢</li></ul><h3 id="扩散模型-diffusion-models" tabindex="-1">扩散模型（Diffusion Models） <a class="header-anchor" href="#扩散模型-diffusion-models" aria-label="Permalink to &quot;扩散模型（Diffusion Models）&quot;">​</a></h3><p>通过学习逆向去噪过程来生成数据。训练时逐步加噪破坏数据，推理时从纯噪声逐步去噪还原。</p><ul><li>代表：Stable Diffusion、DALL·E、Midjourney</li><li>应用：图像生成、视频生成</li><li>特点：生成质量极高，但推理步骤多、速度慢</li></ul><h3 id="gan-生成对抗网络" tabindex="-1">GAN（生成对抗网络） <a class="header-anchor" href="#gan-生成对抗网络" aria-label="Permalink to &quot;GAN（生成对抗网络）&quot;">​</a></h3><p>由<strong>生成器</strong>和<strong>判别器</strong>两个网络相互博弈训练。</p><ul><li>生成器：从随机噪声生成数据，试图&quot;骗过&quot;判别器</li><li>判别器：区分真实数据和生成数据</li><li>代表：StyleGAN、CycleGAN</li><li>特点：生成速度快，但训练不稳定</li></ul><h2 id="aigc-应用场景" tabindex="-1">AIGC 应用场景 <a class="header-anchor" href="#aigc-应用场景" aria-label="Permalink to &quot;AIGC 应用场景&quot;">​</a></h2><p>AIGC（AI Generated Content）正在重塑内容创作方式：</p><ul><li><strong>文本</strong>：ChatGPT 写作、翻译、摘要</li><li><strong>代码</strong>：GitHub Copilot、Cursor 代码补全</li><li><strong>图像</strong>：Midjourney 海报设计、Stable Diffusion 素材生成</li><li><strong>音频</strong>：Suno AI 音乐生成、ElevenLabs 语音合成</li><li><strong>视频</strong>：Sora、Runway 视频生成</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>什么是 AIGC？它给前端开发带来了哪些变化？</li><li>生成式 AI 和以前的 AI 有什么本质不同？</li><li>前端如何集成生成式 AI 的能力？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://en.wikipedia.org/wiki/Generative_artificial_intelligence" target="_blank" rel="noreferrer">Generative AI - Wikipedia</a></li><li><a href="https://www.nvidia.com/en-us/glossary/generative-ai/" target="_blank" rel="noreferrer">What is Generative AI - NVIDIA</a></li></ul>',23)])])}const f=e(l,[["render",o]]);export{g as __pageData,f as default};
